import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const clayLight = '#E2725B'; 
const softCream = '#FDF5E6'; 

function App() {
  // 1. STATE MANAGEMENT
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  // 2. PERSONAL DATA
  const whatsappNumber = "2349122731172";
  const bankInfo = {
    bank: "PREMIUMTRUST BANK",
    account: "0112326977",
    name: "OLUKOYA OMOTOYOSI"
  };

  // 3. PRODUCT DATA
  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection." },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends." },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining." }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people. The ultimate party selection.", img: "/images/owambe.jpg" }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled" }
      ]}
    ]
  };

  // 4. LOGIC
  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => {
    setCart([...cart, item]);
  };

  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. STICKY PREMIUM HEADER */}
      <header style={{ padding: '10px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(10px)', zIndex: 1000, borderBottom: '1px solid #111' }}>
        <img src={Logo} alt="Logo" style={{ height: '55px', width: 'auto', objectFit: 'contain' }} />
        <div style={{ display: 'flex', gap: '18px', fontSize: '1.2rem', color: softCream }}>
          <span style={{ cursor: 'pointer' }} onClick={() => setActiveCategory('About')}>👤</span>
          <span style={{ position: 'relative', cursor: 'pointer' }} onClick={() => setIsCartOpen(true)}>🛒
            <span style={{ position: 'absolute', top: '-5px', right: '-10px', background: terracotta, color: '#fff', borderRadius: '50%', padding: '2px 5px', fontSize: '0.6rem' }}>{cart.length}</span>
          </span>
        </div>
      </header>

      {/* 2. TERRACOTTA HERO BANNER */}
      <div style={{ width: '100%', height: '140px', position: 'relative', overflow: 'hidden', background: `linear-gradient(145deg, ${terracotta} 0%, ${clayLight} 100%)` }}>
        {slides.map((slide, index) => (
          <div key={index} style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', opacity: index === currentSlide ? 1 : 0, transition: 'opacity 1.5s ease-in-out', display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 25px' }}>
            <h2 style={{ fontSize: '1.3rem', color: '#fff', fontWeight: '900', margin: 0, letterSpacing: '1px' }}>{slide.title}</h2>
            <p style={{ fontSize: '0.8rem', color: softCream, margin: '4px 0 0', opacity: 0.8 }}>{slide.subtitle}</p>
          </div>
        ))}
      </div>

      {/* 3. BUSINESS BRANDING */}
      <div style={{ padding: '20px 25px 5px' }}>
        <h1 style={{ fontSize: '1.2rem', margin: '0', color: '#fff', fontWeight: '800' }}>Àmí by T</h1>
        <p style={{ fontSize: '0.7rem', color: '#666', margin: '4px 0 15px' }}>● Opened · Closes 08:00 PM · Ikeja, Lagos</p>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button style={{ flex: 1, padding: '10px', borderRadius: '8px', border: 'none', backgroundColor: softCream, color: '#000', fontWeight: 'bold', fontSize: '0.8rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '10px', borderRadius: '8px', border: `1px solid ${terracotta}`, backgroundColor: 'transparent', color: '#fff', fontSize: '0.8rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. SMOOTH CATEGORY NAV */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '15px 25px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
          <button key={item} onClick={() => {setActiveCategory(item); setShowBankDetails(false);}} style={{ whiteSpace: 'nowrap', padding: '8px 18px', borderRadius: '20px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#111', color: activeCategory === item ? '#fff' : '#888', fontSize: '0.75rem', fontWeight: '700', transition: 'all 0.3s ease' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 5. MAIN CONTENT AREA */}
      <main style={{ paddingBottom: '120px' }}>
        
        {/* SMALL CHOPS SECTION */}
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', margin: '0 25px 12px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
            <div style={{ width: '70px', height: '70px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}>
                <img src={item.img} alt="" style={{width:'100%', height:'100%', objectFit:'cover', borderRadius:'8px'}} onError={(e) => e.target.style.display='none'}/>
            </div>
            <div style={{ flex: 1 }}>
              <h4 style={{ fontSize: '0.9rem', margin: '0', color: '#fff' }}>{item.name}</h4>
              <p style={{ fontSize: '0.65rem', color: '#666', margin: '4px 0' }}>{item.desc}</p>
              <div style={{ fontSize: '1rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
            </div>
            <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '20px', padding: '8px 15px', fontSize: '0.65rem', fontWeight: 'bold' }}>ADD</button>
          </div>
        ))}

        {/* OFFICE LUNCH SECTION */}
        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 25px' }}>
            <div style={{ backgroundColor: '#0A0A0A', border: `1px solid ${isClockedIn ? successGreen : terracotta + '44'}`, padding: '30px 20px', borderRadius: '12px', textAlign: 'center', marginBottom: '20px' }}>
              <h4 style={{ color: isClockedIn ? successGreen : gold, fontSize: '1.1rem' }}>{isClockedIn ? "Enjoy Your Meal, Champion! ✅" : "Good Morning, Champion. ✨"}</h4>
              <button onClick={() => setIsClockedIn(true)} disabled={isClockedIn} style={{ backgroundColor: isClockedIn ? successGreen : terracotta, color: '#fff', border: 'none', padding: '12px 30px', borderRadius: '8px', fontWeight: 'bold', marginTop: '15px' }}>
                {isClockedIn ? "CLOCKED IN" : "CLOCK IN FOR LUNCH"}
              </button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '15px 0', borderBottom: '1px solid #111' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span style={{ color: terracotta, fontWeight: 'bold', fontSize: '0.85rem' }}>{item.day}</span>
                  <span style={{ color: '#fff', fontSize: '0.85rem' }}>{item.meal}</span>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* WIGS SECTION */}
        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 25px', marginBottom: '20px' }}>
            <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '1.5px', marginBottom: '10px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
                <div style={{ width: '60px', height: '60px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}></div>
                <div style={{ flex: 1 }}>
                  <h4 style={{ fontSize: '0.9rem', color: '#fff' }}>{item.name}</h4>
                  <p style={{ fontSize: '0.65rem', color: '#666' }}>{item.desc}</p>
                  <div style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '20px', padding: '8px 15px', fontSize: '0.65rem', fontWeight: 'bold' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}

        {/* ABOUT SECTION */}
        {activeCategory === 'About' && (
          <div style={{ padding: '0 25px', color: '#888', fontSize: '0.85rem', lineHeight: '1.6', textAlign: 'center' }}>
            <h2 style={{ color: gold }}>The Vision</h2>
            <p>Àmí by T is a lifestyle brand dedicated to luxury tastes and premium style in Lagos.</p>
          </div>
        )}
      </main>

      {/* 6. FLOATING CHECKOUT BAR */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)', width: '90%', maxWidth: '400px', backgroundColor: terracotta, padding: '15px', borderRadius: '15px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 10px 25px rgba(0,0,0,0.5)', cursor: 'pointer', zIndex: 1001 }}>
          <div style={{ fontWeight: 'bold' }}>{cart.length} ITEMS</div>
          <div style={{ fontWeight: 'bold' }}>VIEW CART ₦{total.toLocaleString()}</div>
        </div>
      )}

      {/* 7. CART DRAWER (THE PAYMENT LOGIC) */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.95)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#111', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '30px 25px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h3 style={{ color: gold, margin: 0 }}>{showBankDetails ? "Secure Payment" : "Your Selection"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '1.8rem' }}>✕</button>
            </div>

            {!showBankDetails ? (
              <>
                <div style={{ maxHeight: '30vh', overflowY: 'auto' }}>
                  {cart.map((item, index) => (
                    <div key={index} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid #222' }}>
                      <span style={{ fontSize: '0.9rem' }}>{item.name}</span>
                      <div style={{ textAlign: 'right' }}>
                        <span style={{ color: gold }}>₦{item.price}</span>
                        <br/><button onClick={() => removeFromCart(index)} style={{ background: 'none', border: 'none', color: terracotta, fontSize: '0.65rem', padding: 0 }}>Remove</button>
                      </div>
                    </div>
                  ))}
                </div>
                <div style={{ marginTop: '20px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                    <span>Total</span>
                    <span style={{ fontSize: '1.5rem', fontWeight: 'bold', color: gold }}>₦{total.toLocaleString()}</span>
                  </div>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '18px', backgroundColor: gold, border: 'none', borderRadius: '12px', fontWeight: 'bold', marginBottom: '10px' }}>BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Hello ÀMÍ BY T, I'd like to order: ${cart.map(i => i.name).join(', ')}. Total: ₦${total.toLocaleString()}`)} style={{ width: '100%', padding: '18px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: 'bold' }}>ORDER ON WHATSAPP</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ color: gold }}>₦{total.toLocaleString()}</h2>
                <div style={{ backgroundColor: '#000', padding: '20px', borderRadius: '12px', textAlign: 'left', border: `1px solid ${gold}33` }}>
                  <p><strong>Bank:</strong> {bankInfo.bank}</p>
                  <p><strong>Account:</strong> {bankInfo.account}</p>
                  <p><strong>Name:</strong> {bankInfo.name}</p>
                </div>
                <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=I have made a transfer of ₦${total.toLocaleString()} for my order.`)} style={{ width: '100%', marginTop: '20px', padding: '18px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: 'bold' }}>SEND RECEIPT</button>
                <button onClick={() => setShowBankDetails(false)} style={{ background: 'none', border: 'none', color: '#555', marginTop: '15px', textDecoration: 'underline' }}>Back to Cart</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
